#!/usr/bin/env node
// Sync ../docs/*.md into src/content/docs so Starlight renders them.
// docs/*.md remains the source of truth; this script generates the Starlight
// copies on every build (predev / prebuild). Generated files are gitignored.

import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, '../..');
const docsDir = resolve(repoRoot, 'docs');
const outDir = resolve(__dirname, '../src/content/docs');

// Source filename → { target path relative to outDir, generated description fallback }.
// `null` target = skip (rendered elsewhere or replaced by a deploy redirect).
const MAP = {
  '1-overview.md': { target: 'docs/overview.md', description: 'What Kerf is, why it exists, when to use it.' },
  '2-reactivity.md': { target: 'docs/reactivity.md', description: 'Signals, computeds, effects, batch.' },
  '3-stores.md': { target: 'docs/stores.md', description: 'defineStore — composable, testable state.' },
  '4-render.md': { target: 'docs/render.md', description: 'mount, segments, the native diff, the keyed list reconciler.' },
  '5-event-delegation.md': { target: 'docs/events.md', description: 'Tier 1 / Tier 2 / Tier 3 listener model — delegate and delegateCapture.' },
  '6-jsx-runtime.md': { target: 'docs/jsx.md', description: 'JSX → HTML strings, server use, SafeHtml.' },
  '7-svg.md': { target: 'docs/svg.md', description: 'Namespace handling, toElement.' },
  '8-api-reference.md': { target: 'api.md', description: 'Every export from kerfjs at a glance.' },
  '9-live-demo.md': { target: null }, // sidebar links straight to /kerf/demo/
  '10-migrating.md': { target: null }, // design doc — the rendered hub lives at site/src/content/docs/migrating/
  '11-dev-warnings.md': { target: 'docs/dev-warnings.md', description: 'Opt-in dev-mode warnings — KERF_DEV_WARN_REBUILT_LISTENERS / KERF_DEV_WARN_UNTRACKED_SIGNALS / KERF_DEV_WARN_NARROW_SET.' },
};

// Slug rewrites for inter-doc links: `(N-name.md)` and `(N-name.md#anchor)`
// in the source need to point at the Starlight slug, which lives under /kerf/.
// Keep this aligned with MAP above.
const LINK_REWRITE = {
  '1-overview.md': '/kerf/docs/overview/',
  '2-reactivity.md': '/kerf/docs/reactivity/',
  '3-stores.md': '/kerf/docs/stores/',
  '4-render.md': '/kerf/docs/render/',
  '5-event-delegation.md': '/kerf/docs/events/',
  '6-jsx-runtime.md': '/kerf/docs/jsx/',
  '7-svg.md': '/kerf/docs/svg/',
  '8-api-reference.md': '/kerf/api/',
  '9-live-demo.md': '/kerf/demo/',
  '10-migrating.md': '/kerf/migrating/',
  '11-dev-warnings.md': '/kerf/docs/dev-warnings/',
};

const HEADER = `<!-- AUTOGENERATED by site/scripts/sync-docs.mjs from docs/{src}. Do not edit by hand — edit the source doc and re-run \`npm run sync-docs\`. -->`;

function extractTitle(body) {
  const m = body.match(/^#\s+(?:\d+\.\s+)?(.+?)\s*$/m);
  return m ? m[1].trim() : null;
}

function stripFirstH1(body) {
  return body.replace(/^#\s+[^\n]*\n+/, '');
}

function rewriteLinks(body) {
  return body.replace(/\(([0-9]+-[a-z-]+\.md)(#[^)]*)?\)/g, (_, file, anchor) => {
    const slug = LINK_REWRITE[file];
    if (!slug) return `(${file}${anchor ?? ''})`;
    return `(${slug}${anchor ?? ''})`;
  });
}

function escapeYaml(s) {
  return s.replace(/'/g, "''");
}

async function syncOne(srcName, { target, description }) {
  const srcPath = resolve(docsDir, srcName);
  const raw = await readFile(srcPath, 'utf8');
  const title = extractTitle(raw) ?? srcName;
  let body = stripFirstH1(raw);
  body = rewriteLinks(body);

  const frontmatter = [
    '---',
    `title: '${escapeYaml(title)}'`,
    `description: '${escapeYaml(description)}'`,
    '---',
    '',
    HEADER.replace('{src}', srcName),
    '',
  ].join('\n');

  const outPath = resolve(outDir, target);
  await mkdir(dirname(outPath), { recursive: true });
  await writeFile(outPath, frontmatter + body, 'utf8');
  return outPath;
}

async function main() {
  const written = [];
  for (const [srcName, cfg] of Object.entries(MAP)) {
    if (!cfg.target) continue;
    const outPath = await syncOne(srcName, cfg);
    written.push(outPath);
  }
  // KF-211: the published /ai marketing page was removed along with the
  // /ai-evidence/ tree. `docs/ai/usage-guide.md` stays as the canonical
  // AI-tool reference (fetched directly by llms.txt-aware assistants); it
  // is no longer mirrored as a Starlight page.
  // eslint-disable-next-line no-console
  console.log(`[sync-docs] wrote ${written.length} files`);
}

main().catch((err) => {
  // eslint-disable-next-line no-console
  console.error('[sync-docs] failed:', err);
  process.exit(1);
});
